/*
 * RSA Algorithm Implementation in C
 * Demonstrates key generation, encryption, and decryption
 * Using example values: p=61, q=53
 */

#include <stdio.h>
#include <stdlib.h>

// Structure to hold RSA keys
typedef struct {
    long long exponent;  // e for public, d for private
    long long modulus;   // n
} RSA_Key;

// Extended Euclidean Algorithm
// Returns gcd(a, b) and finds x, y such that a*x + b*y = gcd(a, b)
long long extended_gcd(long long a, long long b, long long *x, long long *y) {
    if (a == 0) {
        *x = 0;
        *y = 1;
        return b;
    }

    long long x1, y1;
    long long gcd = extended_gcd(b % a, a, &x1, &y1);

    *x = y1 - (b / a) * x1;
    *y = x1;

    return gcd;
}

// Compute modular multiplicative inverse: d = a^(-1) mod m
long long mod_inverse(long long a, long long m) {
    long long x, y;
    long long g = extended_gcd(a, m, &x, &y);

    if (g != 1) {
        printf("Error: Modular inverse does not exist\n");
        return -1;
    }

    // Make sure x is positive
    x = (x % m + m) % m;
    return x;
}

// Modular Exponentiation using Square-and-Multiply
// Computes (base^exp) mod mod efficiently: O(log exp)
long long mod_pow(long long base, long long exp, long long mod) {
    long long result = 1;
    base = base % mod;

    while (exp > 0) {
        // If exp is odd, multiply result with base
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }

        // Square the base
        exp = exp / 2;
        base = (base * base) % mod;
    }

    return result;
}

// RSA Key Generation
void generate_keys(long long p, long long q, RSA_Key *public_key, RSA_Key *private_key) {
    long long n, phi_n, e, d;

    // Step 1: Compute modulus n = p * q
    n = p * q;
    printf("Step 1: n = p * q = %lld * %lld = %lld\n", p, q, n);

    // Step 2: Compute Euler's totient φ(n) = (p-1)(q-1)
    phi_n = (p - 1) * (q - 1);
    printf("Step 2: φ(n) = (p-1)(q-1) = %lld * %lld = %lld\n", 
           p-1, q-1, phi_n);

    // Step 3: Choose public exponent e
    // Must satisfy: 1 < e < φ(n) and gcd(e, φ(n)) = 1
    e = 17;  // Common choice for efficiency

    // Verify e is coprime to φ(n)
    long long x, y;
    if (extended_gcd(e, phi_n, &x, &y) != 1) {
        printf("Error: e is not coprime to φ(n)\n");
        return;
    }

    printf("Step 3: Choose e = %lld (coprime to φ(n))\n", e);

    // Step 4: Compute private exponent d
    // d = e^(-1) mod φ(n)
    d = mod_inverse(e, phi_n);
    printf("Step 4: d = e^(-1) mod φ(n) = %lld\n", d);
    printf("        Verification: (%lld * %lld) mod %lld = %lld\n", 
           d, e, phi_n, (d * e) % phi_n);

    // Set key values
    public_key->exponent = e;
    public_key->modulus = n;

    private_key->exponent = d;
    private_key->modulus = n;
}

// RSA Encryption: C = M^e mod n
long long encrypt(long long message, RSA_Key public_key) {
    return mod_pow(message, public_key.exponent, public_key.modulus);
}

// RSA Decryption: M = C^d mod n
long long decrypt(long long ciphertext, RSA_Key private_key) {
    return mod_pow(ciphertext, private_key.exponent, private_key.modulus);
}

// Main demonstration
int main() {
    long long p = 61, q = 53;
    long long plaintext = 65;  // ASCII value for 'A'
    long long ciphertext, decrypted;

    RSA_Key public_key, private_key;

    printf("============================================\n");
    printf("RSA Algorithm Implementation in C\n");
    printf("Example: p = %lld, q = %lld\n", p, q);
    printf("============================================\n\n");

    // Generate RSA keys
    generate_keys(p, q, &public_key, &private_key);

    printf("\n============================================\n");
    printf("Generated Keys:\n");
    printf("Public Key (e, n):  (%lld, %lld)\n", 
           public_key.exponent, public_key.modulus);
    printf("Private Key (d, n): (%lld, %lld)\n", 
           private_key.exponent, private_key.modulus);
    printf("============================================\n\n");

    // Encryption
    printf("Encryption:\n");
    printf("  Plaintext M = %lld (ASCII for 'A')\n", plaintext);
    ciphertext = encrypt(plaintext, public_key);
    printf("  Ciphertext C = M^e mod n\n");
    printf("  C = %lld^%lld mod %lld = %lld\n", 
           plaintext, public_key.exponent, public_key.modulus, ciphertext);

    // Decryption
    printf("\nDecryption:\n");
    printf("  Ciphertext C = %lld\n", ciphertext);
    decrypted = decrypt(ciphertext, private_key);
    printf("  Plaintext M = C^d mod n\n");
    printf("  M = %lld^%lld mod %lld = %lld\n", 
           ciphertext, private_key.exponent, private_key.modulus, decrypted);

    // Verification
    printf("\n============================================\n");
    printf("Verification: %lld == %lld ? %s\n", 
           plaintext, decrypted, 
           (plaintext == decrypted) ? "SUCCESS" : "FAILED");
    printf("============================================\n");

    return 0;
}
